<script setup>
import { ref, onMounted } from 'vue';
import { onShow } from '@dcloudio/uni-app';

// 检查登录状态
onMounted(async () => {
  const token = uni.getStorageSync('token');
  if (!token) {
    uni.navigateTo({
      url: '/pages/login/login'
    });
    return;
  }
  
  // 获取当前用户信息
  await fetchUserInfo();
});

// 监听页面显示，重新获取用户信息
onShow(async () => {
  const token = uni.getStorageSync('token');
  if (token) {
    await fetchUserInfo();
  }
});

// 用户数据
const userInfo = ref({
  name: '默认用户',
  avatar: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=student%20avatar%20default&image_size=square',
  college: '默认学院',
  skills: [],
  notification: true
});

// 加载状态
const loading = ref(true);

// 获取用户信息
const fetchUserInfo = async () => {
  try {
    loading.value = true;
    const token = uni.getStorageSync('token');
    
    const userInfoFromStorage = uni.getStorageSync('userInfo');
    const userId = userInfoFromStorage?.id;
    
    const response = await uni.request({
      url: `http://localhost:3000/api/users/${userId}`,
      method: 'GET',
      header: {
        'Authorization': `Bearer ${token}`
      }
    });
    
    if (response.data && response.data.success) {
      userInfo.value = {
        ...response.data.data,
        skills: response.data.data.skills || [],
        notification: response.data.data.notificationEnabled || true
      };
    } else {
      uni.showToast({
        title: '获取用户信息失败',
        icon: 'none'
      });
      // 使用默认数据
      userInfo.value = {
        name: '张三',
        avatar: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=student%20avatar%20male&image_size=square',
        college: '计算机学院',
        skills: ['Vue', 'JavaScript', 'Java', 'Python'],
        notification: true
      };
    }
  } catch (error) {
    console.error('获取用户信息错误:', error);
    uni.showToast({
      title: '网络错误，请稍后重试',
      icon: 'none'
    });
    // 使用默认数据
    userInfo.value = {
      name: '默认用户',
      avatar: 'https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=student%20avatar%20default&image_size=square',
      college: '默认学院',
      skills: [],
      notification: true
    };
  } finally {
    loading.value = false;
  }
};

// 编辑个人资料
const editProfile = () => {
  console.log('编辑个人资料');
};

// 编辑技能
const editSkills = () => {
  uni.navigateTo({
    url: '/pages/profile/edit-profile'
  });
};

// 添加技能
const addSkill = () => {
  console.log('添加技能');
};

// 获取技能标签颜色
const getSkillColor = (index) => {
  const colors = ['#4A90E2', '#50E3C2', '#F5A623', '#D0021B'];
  return colors[index % colors.length];
};

// 跳转到身份认证
const goToAuth = () => {
  console.log('跳转到身份认证');
};

// 跳转到编辑信息页面
const goToPrivacy = () => {
  console.log('跳转到编辑信息页面');
  uni.navigateTo({
    url: '/pages/profile/edit-profile'
  });
};

// 跳转到我的发布页面
const goToMyPosts = () => {
  console.log('跳转到我的发布页面');
  uni.navigateTo({
    url: '/pages/profile/my-posts'
  });
};

// 切换通知
const toggleNotification = async () => {
  try {
    const token = uni.getStorageSync('token');
    const userId = uni.getStorageSync('userInfo')?.id;
    
    if (!token || !userId) {
      uni.showToast({
        title: '请先登录',
        icon: 'none'
      });
      return;
    }
    
    const response = await uni.request({
      url: `http://localhost:3000/api/users/${userId}`,
      method: 'PUT',
      header: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      data: {
        notificationEnabled: !userInfo.value.notification
      }
    });
    
    if (response.data && response.data.success) {
      userInfo.value.notification = !userInfo.value.notification;
      uni.showToast({
        title: '设置成功',
        icon: 'success'
      });
    } else {
      uni.showToast({
        title: '设置失败',
        icon: 'none'
      });
    }
  } catch (error) {
    console.error('切换通知状态错误:', error);
    uni.showToast({
      title: '网络错误，请稍后重试',
      icon: 'none'
    });
  }
};

// 更换头像
const changeAvatar = () => {
  uni.chooseImage({
    count: 1,
    sizeType: ['original', 'compressed'],
    sourceType: ['album', 'camera'],
    success: function(res) {
      const tempFilePaths = res.tempFilePaths;
      uploadAvatar(tempFilePaths[0]);
    }
  });
};

// 上传头像
const uploadAvatar = async (tempFilePath) => {
  try {
    const token = uni.getStorageSync('token');
    const userId = uni.getStorageSync('userInfo')?.id;
    
    if (!token || !userId) {
      uni.showToast({
        title: '请先登录',
        icon: 'none'
      });
      return;
    }
    
    uni.showLoading({ title: '上传中...' });
    
    const uploadTask = uni.uploadFile({
      url: 'http://localhost:3000/api/users/avatar',
      filePath: tempFilePath,
      name: 'avatar',
      header: {
        'Authorization': `Bearer ${token}`
      },
      formData: {
        'userId': userId
      },
      success: async function(uploadRes) {
        try {
          const response = JSON.parse(uploadRes.data);
          if (response && response.success) {
            // 更新本地头像
            userInfo.value.avatar = response.data.avatar;
            // 更新本地存储中的用户信息
            const userInfoFromStorage = uni.getStorageSync('userInfo');
            userInfoFromStorage.avatar = response.data.avatar;
            uni.setStorageSync('userInfo', userInfoFromStorage);
            
            uni.showToast({
              title: '头像上传成功',
              icon: 'success'
            });
          } else {
            uni.showToast({
              title: '上传失败，请稍后重试',
              icon: 'none'
            });
          }
        } catch (error) {
          console.error('解析上传响应错误:', error);
          uni.showToast({
            title: '上传失败，请稍后重试',
            icon: 'none'
          });
        }
      },
      fail: function(error) {
        console.error('上传头像错误:', error);
        uni.showToast({
          title: '上传失败，请稍后重试',
          icon: 'none'
        });
      },
      complete: function() {
        uni.hideLoading();
      }
    });
  } catch (error) {
    console.error('上传头像错误:', error);
    uni.hideLoading();
    uni.showToast({
      title: '网络错误，请稍后重试',
      icon: 'none'
    });
  }
};

// 退出登录
const logout = () => {
  uni.showModal({
    title: '退出登录',
    content: '确定要退出登录吗？',
    success: function(res) {
      if (res.confirm) {
        // 清除本地存储
        uni.removeStorageSync('token');
        uni.removeStorageSync('userInfo');
        
        // 跳转到登录页面
        uni.navigateTo({
          url: '/pages/login/login'
        });
      }
    }
  });
};
</script>

